// KST 기준 지난달 범위 계산
const now = new Date();
const kstNow = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const year = kstNow.getUTCFullYear();
const month = kstNow.getUTCMonth(); // 0-indexed: 현재달

// 지난달 첫날 (UTC)
const lastMonthStart = new Date(Date.UTC(year, month - 1, 1));
// 이번달 첫날 (UTC)
const thisMonthStart = new Date(Date.UTC(year, month, 1));

const startStr = lastMonthStart.toISOString().split('T')[0];
const endStr = thisMonthStart.toISOString().split('T')[0];

// NocoDB where 필터 (수집일시 기준)
const nocodbWhere = `(수집일시,gte,${startStr})~and(수집일시,lt,${endStr})`;

const reportMonth = `${year}년 ${month}월`;

return [{ json: { nocodbWhere, reportMonth, startStr, endStr } }];

const rawItems = $input.all();
const reportMonth = $('Code_날짜계산').first().json.reportMonth;

// NocoDB 리스트 응답 확장
const items = [];
for (const raw of rawItems) {
  if (raw.json.list && Array.isArray(raw.json.list)) {
    for (const record of raw.json.list) {
      items.push({ json: record });
    }
  } else if (!raw.json.error) {
    items.push(raw);
  }
}

if (!items || items.length === 0 || (items.length === 1 && items[0].json.error)) {
  return [{ json: { reportMonth, totalCount: 0, 긴급검토: 0, 검토권장: 0, 저관련: 0, 신청완료: 0, 미신청: 0, 미검토: 0, 기간만료: 0, 기업마당: 0, kStartup: 0, 보조금24: 0, avgScore: 0 } }];
}

const counts = { 긴급검토: 0, 검토권장: 0, 저관련: 0 };
const statusCounts = { 신청완료: 0, 미신청: 0, 미검토: 0, 기간만료: 0 };
const sourceCounts = { 기업마당: 0, kStartup: 0, 보조금24: 0 };
let totalScore = 0, scoreCount = 0;

for (const item of items) {
  const f = item.json;
  const score = Number(f['관련도점수'] || 0);
  const status = f['상태'] || '';
  const source = f['출처'] || '';

  // 관련지수 분류
  if (score >= 70) counts.긴급검토++;
  else if (score >= 30) counts.검토권장++;
  else counts.저관련++;

  // 상태 분류
  if (status === '지원 완료' || status === '작성 완료') statusCounts.신청완료++;
  else if (status === '기간만료' || status === '탈락') statusCounts.기간만료++;
  else if (status === '작성 중') statusCounts.미신청++;
  else statusCounts.미검토++;

  // 수집 소스
  if (source === '기업마당') sourceCounts.기업마당++;
  else if (source === 'K-Startup') sourceCounts.kStartup++;
  else if (source === '보조금24') sourceCounts.보조금24++;

  if (score > 0) { totalScore += score; scoreCount++; }
}

const avgScore = scoreCount > 0 ? (totalScore / scoreCount).toFixed(1) : '0';

return [{ json: {
  reportMonth,
  totalCount: items.length,
  긴급검토: counts.긴급검토,
  검토권장: counts.검토권장,
  저관련: counts.저관련,
  신청완료: statusCounts.신청완료,
  미신청: statusCounts.미신청,
  미검토: statusCounts.미검토,
  기간만료: statusCounts.기간만료,
  기업마당: sourceCounts.기업마당,
  kStartup: sourceCounts.kStartup,
  보조금24: sourceCounts.보조금24,
  avgScore
} }];
